sql:
SELECT store_nbr, sales
FROM store_performance
WHERE date = '2023-10-02' AND sales > 1000.0;

external_knowledge:
- "dawn of the new decade" refers to the start of 2020;
- "blossomed in their sales" refers to stores that have recorded sales data;
- "average performance" refers to the average sales amount.

sql:
SELECT store_nbr, AVG(sales) AS avg_sales
FROM store_performance
GROUP BY store_nbr;

SELECT AVG(sales) AS average_sales
FROM store_performance
WHERE date IN (SELECT date FROM holidays WHERE national_holi = 1);

external_knowledge:
